mapper.select:
SELECT r.id, CONCAT(u.user_name, CASE r.event_type WHEN 1 THEN '点赞了你的内容' WHEN 2 THEN '评论了你的内容' WHEN 3 THEN '关注了你' WHEN 4 THEN '转发了你的内容' WHEN 5 THEN '@了你' ELSE '' END ) AS title, r.summary, r.jump_url AS jumpUrl, r.is_read AS isRead, r.create_time AS createTime FROM msg_event_remind r LEFT JOIN sys_user u ON r.sender_id = u.id WHERE r.user_id = #{userId}
AND r.is_read = #{isRead}
ORDER BY r.create_time DESC LIMIT #{offset}, #{size}
